import type { PaginationParams, PaginatedResponse, Product, Category } from '~/types'

export function useProductsApi() {
    const { $api } = useNuxtApp()

    return {
        findAll(params?: PaginationParams & { category?: string; isActive?: boolean }) {
            return $api<PaginatedResponse<Product>>('/products/admin/list', { params })
        },
        findById(id: string) {
            return $api<Product>(`/products/${id}`)
        },
        findBySlug(slug: string) {
            return $api<Product>(`/products/slug/${slug}`)
        },
        create(data: Partial<Product>) {
            return $api<any>('/products', { method: 'POST', body: data })
        },
        update(id: string, data: Partial<Product>) {
            return $api<any>(`/products/${id}`, { method: 'PUT', body: data })
        },
        delete(id: string) {
            return $api<any>(`/products/${id}`, { method: 'DELETE' })
        },
        // Categories
        getCategories() {
            return $api<Category[]>('/products/categories/all')
        },
        createCategory(data: Partial<Category>) {
            return $api<any>('/products/categories', { method: 'POST', body: data })
        },
        updateCategory(id: string, data: Partial<Category>) {
            return $api<any>(`/products/categories/${id}`, { method: 'PUT', body: data })
        },
        deleteCategory(id: string) {
            return $api<any>(`/products/categories/${id}`, { method: 'DELETE' })
        },
    }
}
